import{_ as n,o as t,c as i,a8 as o}from"./chunks/framework.DvHWw5tv.js";const g=JSON.parse('{"title":"mengyue-plus","description":"","frontmatter":{},"headers":[],"relativePath":"en/plugin/mengyuePlus.md","filePath":"en/plugin/mengyuePlus.md"}'),a={name:"en/plugin/mengyuePlus.md"};function s(r,e,l,c,d,p){return t(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[o('<h1 id="mengyue-plus" tabindex="-1">mengyue-plus <a class="header-anchor" href="#mengyue-plus" aria-label="Permalink to “mengyue-plus”">​</a></h1><p><code>mengyue-plus</code> is an <strong>early transitional version</strong> of this component library system prior to its official release. It embodies the initial design concepts and functional implementations of the component library, laying a solid foundation for the subsequent formal version&#39;s refinement.</p><p>Positioning and Current Status</p><p><code>mengyue-plus</code> is <strong>fully consistent</strong> with the official version <code>mengyue-components</code> in terms of component types, featuring all the functionalities of basic components. This version was previously used for internal validation and early project trials. With the release of the official version, <code>mengyue-plus</code> has entered a <strong>maintenance freeze</strong> state and will no longer receive new feature developments.</p><h2 id="technical-features" tabindex="-1">Technical Features <a class="header-anchor" href="#technical-features" aria-label="Permalink to “Technical Features”">​</a></h2><ul><li><strong>Technology Stack</strong>: Vue 3 + TypeScript + Vite, built on pnpm workspace.</li><li><strong>Fully自主研发</strong>：All components are independently developed without relying on any third-party UI libraries.</li><li><strong>Test Assurance</strong>: Includes over 200 test cases with 100% unit test coverage.</li><li><strong>Lightweight Design</strong>: The package size is controlled at the hundreds of KB level (&lt;1MB), with minimal cost for on-demand integration.</li></ul><h2 id="relationship-with-the-official-version" tabindex="-1">Relationship with the Official Version <a class="header-anchor" href="#relationship-with-the-official-version" aria-label="Permalink to “Relationship with the Official Version”">​</a></h2><p><code>mengyue-plus</code> and <code>mengyue-components</code> have an <strong>inheritance and optimization relationship</strong>:</p><p>The official version retains all component functionalities while <strong>unifying and optimizing the Props API design</strong>, enhancing usage consistency.</p><ul><li>Fixed defects identified in earlier versions, enhancing code robustness and maintainability.</li></ul><div class="warning custom-block"><p class="custom-block-title">Migration Recommendation</p><p>If the current project is still using <code>mengyue-plus</code>, <strong>strongly recommend migrating to the official version <code>mengyue-components</code></strong>.<br> For migration paths and change points, please refer to the independent <a href="./../question/migration.html">Migration Guide</a> section.</p></div><h2 id="precautions" tabindex="-1">Precautions <a class="header-anchor" href="#precautions" aria-label="Permalink to “Precautions”">​</a></h2><p>Although <code>mengyue-plus</code> and <code>mengyue-components</code> can coexist in the same project, they represent different iterations of the same component set, so <strong>there is no need to import both simultaneously</strong>.</p><ul><li>All future new features and bug fixes will be <strong>implemented in <code>mengyue-components</code></strong>.</li></ul><p>For new projects, please directly use <code>mengyue-components</code> to access the latest API design and long-term maintenance support.</p>',15)])])}const h=n(a,[["render",s]]);export{g as __pageData,h as default};
